#include <stdio.h>
#include <string.h>

#define MAXV 100000

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int a[1000];
        static int freq[MAXV + 1];
        memset(freq, 0, sizeof(freq));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
            ++freq[a[i]];
        }
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                int sum = a[i] + a[j];
                if (sum <= MAXV) ans += freq[sum];
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

